package main

import (
	"bufio"
	"bytes"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings a specified host a given number of times and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be positive")
	}
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	var cmd *exec.Cmd

	// Build the ping command based on the operating system
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		// Linux, macOS, and other Unix-like systems
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Execute the command and capture output
	var stdout, stderr bytes.Buffer
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr

	err := cmd.Run()
	output := stdout.String()

	// Even if there's an error, we might still have valid latency data
	// (e.g., partial packet loss)
	latencies, parseErr := parsePingOutput(output)

	if parseErr != nil || len(latencies) == 0 {
		if err != nil {
			return 0, fmt.Errorf("ping command failed: %w, stderr: %s", err, stderr.String())
		}
		return 0, fmt.Errorf("no latency values found in ping output")
	}

	// Calculate average latency
	var sum float64
	for _, latency := range latencies {
		sum += latency
	}

	return sum / float64(len(latencies)), nil
}

// parsePingOutput extracts latency values from ping command output
func parsePingOutput(output string) ([]float64, error) {
	var latencies []float64

	// Regular expression to match latency in ping output
	// Matches patterns like: time=1.23 ms, time=1.23ms, time<1ms
	// This works for both Linux/macOS and Windows formats
	re := regexp.MustCompile(`time[=<]([\d.]+)\s*ms`)

	scanner := bufio.NewScanner(strings.NewReader(output))
	for scanner.Scan() {
		line := scanner.Text()
		matches := re.FindStringSubmatch(line)
		if len(matches) > 1 {
			latency, err := strconv.ParseFloat(matches[1], 64)
			if err != nil {
