		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Capture the output
	output, err := cmd.CombinedOutput()
	if err != nil {
		// Even if there's an error, we might still have output to parse
		avg, parseErr := parsePingOutput(string(output))
		if parseErr == nil {
