package main

import (
	"bufio"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host a given number of times and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be positive, got %d", count)
	}
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	var cmd *exec.Cmd

	// Use appropriate ping command based on OS
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		// Linux, macOS, and other Unix-like systems
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Execute the ping command
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w", err)
	}

	// Parse the output to extract latency values
	return parsePingOutput(string(output))
}

// parsePingOutput extracts latency values from ping command output
func parsePingOutput(output string) (float64, error) {
	var latencies []float64
	scanner := bufio.NewScanner(strings.NewReader(output))

	// Regular expressions for different ping output formats
	// Linux/macOS format: time=14.2 ms or time=14.2ms
	linuxRegex := regexp.MustCompile(`time=(\d+\.?\d*)\s*ms`)
	// Windows format: time=14ms or time<1ms
	windowsRegex := regexp.MustCompile(`time[=<](\d+)ms`)

	for scanner.Scan() {
		line := scanner.Text()

		// Try Linux/macOS format first
		if matches := linuxRegex.FindStringSubmatch(line); len(matches) > 1 {
			if latency, err := strconv.ParseFloat(matches[1], 64); err == nil {
				latencies = append(latencies, latency)
			}
			continue
		}

		// Try Windows format
		if matches := windowsRegex.FindStringSubmatch(line); len(matches) > 1 {
			if latency, err := strconv.ParseFloat(matches[1], 64); err == nil {
				latencies = append(latencies, latency)
			}
		}
	}

	if err := scanner.Err(); err != nil {
		return 0, fmt.Errorf("error reading ping output: %w", err)
	}

	if len(latencies) == 0 {
		return 0, fmt.Errorf("could not parse any latency values from ping output")
	}

	// Calculate average latency
	var sum float64
	for _, latency := range latencies {
		sum += latency
	}

	return sum / float64(len(latencies)), nil
}

func main() {
	// Example usage
	host := "google.com"
	count := 4

	fmt.Printf("Measuring latency to %s (%d pings)...\n", host, count)

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s: %.2f ms\n", host, avgLatency)
}

