package main

import (
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency pings the specified host count times and returns the average latency in milliseconds.
// It uses the system's ping command and parses the output to extract latency values.
func MeasureLatency(host string, count int) (float64, error) {
	// Validate input parameters
	if count <= 0 {
		return 0, fmt.Errorf("count must be greater than 0")
	}
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	var cmd *exec.Cmd

	// Use appropriate ping flags based on operating system
	// Windows uses -n for count, Unix-like systems use -c
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Execute the ping command and capture output
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping command: %w", err)
	}

	// Parse the output to extract latency values
	latencies := parsePingOutput(string(output))

	if len(latencies) == 0 {
		return 0, fmt.Errorf("no latency values found in ping output")
	}

	// Calculate average latency
	var sum float64
	for _, lat := range latencies {
		sum += lat
	}

	averageLatency := sum / float64(len(latencies))
	return averageLatency, nil
}

// parsePingOutput extracts latency values from ping command output.
// It handles both Unix-like and Windows ping output formats.
func parsePingOutput(output string) []float64 {
	var latencies []float64

	// Regular expression to match time values in ping output
	// Handles formats:
	// - Unix/macOS: time=XX.X ms or time=XX.Xms
	// - Windows: time=XXms or time<XXms
	regex := regexp.MustCompile(`time[=<](\d+\.?\d*)\s*ms`)

	matches := regex.FindAllStringSubmatch(output, -1)

	for _, match := range matches {
		if len(match) > 1 {
			lat, err := strconv.ParseFloat(match[1], 64)
			if err != nil {
				continue
			}
			latencies = append(latencies, lat)
		}
	}

	return latencies
}

func main() {
	// Example usage
	host := "google.com"
	count := 4

	fmt.Printf("Measuring latency to %s (%d pings)...\n", host, count)

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency to %s: %.2f ms\n", host, avgLatency)
}

