package main

import (
	"bufio"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns
// the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be positive, got %d", count)
	}
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	var cmd *exec.Cmd

	// Different ping command syntax for different OS
	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	default:
		// Unix-like systems (Linux, macOS, etc.)
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		// Even if ping command failed, try to parse any successful responses
		latencies := parsePingOutput(string(output))
		if len(latencies) > 0 {
			var sum float64
			for _, lat := range latencies {
				sum += lat
			}
			return sum / float64(len(latencies)), nil
		}
		return 0, fmt.Errorf("ping command failed: %w", err)
	}

	// Parse the output to extract latency values
	latencies := parsePingOutput(string(output))

	if len(latencies) == 0 {
		return 0, fmt.Errorf("no latency values found in ping output")
	}

	// Calculate average
	var sum float64
	for _, lat := range latencies {
		sum += lat
	}

	return sum / float64(len(latencies)), nil
}

// parsePingOutput extracts latency values from ping command output.
func parsePingOutput(output string) []float64 {
	var latencies []float64

	// Regular expression to match time values (case-insensitive)
	// Handles formats like:
	// - time=0.123 ms (Unix/Linux)
	// - time=0.123ms (macOS)
	// - time=14ms (Windows)
	// - time<1ms (Windows, less than 1ms)
	timeRegex := regexp.MustCompile(`(?i)time[=<>]([\d.]+)\s*ms`)

	scanner := bufio.NewScanner(strings.NewReader(output))
	for scanner.Scan() {
		line := scanner.Text()
		matches := timeRegex.FindStringSubmatch(line)
		if len(matches) > 1 {
			lat, err := strconv.ParseFloat(matches[1], 64)
			if err != nil {
				continue
			}
			latencies = append(latencies, lat)
		}
	}

	return latencies
}

func main() {
	// Example usage
	host := "google.com"
	count := 4

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency to %s: %.2f ms\n", host, avgLatency)
}

