	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host a given number of times and returns
// the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be positive")
	}
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	var cmd *exec.Cmd

	// Different ping commands for different OS
	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	default:
		// Linux, macOS, and other Unix-like systems
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Use CombinedOutput to capture both stdout and stderr
	output, err := cmd.CombinedOutput()
	if err != nil {
		// Still try to parse output even if command returned non-zero exit code
		// (e.g., when some packets are lost)
		if len(output) == 0 {
			return 0, fmt.Errorf("ping command failed: %w", err)
		}
	}

	// Parse the output to extract latency values
	return parsePingOutput(string(output), runtime.GOOS)
}

// parsePingOutput extracts latency values from ping command output
func parsePingOutput(output string, goos string) (float64, error) {
	scanner := bufio.NewScanner(strings.NewReader(output))
	var latencies []float64

	// Regex patterns for different formats
	// Linux/macOS: time=14.2 ms or time=14.2ms
	linuxPattern := regexp.MustCompile(`time=([0-9.]+)\s*ms`)
	// Windows: time=14ms or time<1ms
	windowsPattern := regexp.MustCompile(`time[=<]([0-9.]+)ms`)

	for scanner.Scan() {
		line := scanner.Text()

		var matches []string
		if goos == "windows" {
			matches = windowsPattern.FindStringSubmatch(line)
		} else {
			matches = linuxPattern.FindStringSubmatch(line)
		}

		if len(matches) > 1 {
			if lat, err := strconv.ParseFloat(matches[1], 64); err == nil {
				latencies = append(latencies, lat)
			}
		}
	}

	if len(latencies) == 0 {
		return 0, fmt.Errorf("could not parse any latency values from ping output")
	}

	var sum float64
	for _, lat := range latencies {
		sum += lat
	}

	return sum / float64(len(latencies)), nil
}

func main() {
	// Example usage
	host := "google.com"
	count := 4

	fmt.Printf("Measuring latency to %s (%d pings)...\n", host, count)

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error measuring latency: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s: %.2f ms\n", host, avgLatency)
}

