package main

import (
	"bufio"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns
// the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}
	if count <= 0 {
		return 0, fmt.Errorf("count must be positive")
	}

	// Build the ping command based on OS
	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Execute the command
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w, output: %s", err, string(output))
	}

	// Parse the output to extract latency values
	latencies, err := parsePingOutput(string(output))
	if err != nil {
		return 0, err
	}

	if len(latencies) == 0 {
		return 0, fmt.Errorf("no latency values found in ping output")
	}

	// Calculate average latency
	var sum float64
	for _, lat := range latencies {
		sum += lat
	}

	return sum / float64(len(latencies)), nil
}

// parsePingOutput extracts latency values from ping command output
func parsePingOutput(output string) ([]float64, error) {
	var latencies []float64

	// Regular expression to match time values in ping output
	// Matches patterns like "time=1.23 ms", "time=1.234ms", "time<1ms"
	re := regexp.MustCompile(`time[=<>](\d+\.?\d*)\s*ms`)

	scanner := bufio.NewScanner(strings.NewReader(output))
	for scanner.Scan() {
		line := scanner.Text()
		matches := re.FindStringSubmatch(line)
		if len(matches) > 1 {
			lat, err := strconv.ParseFloat(matches[1], 64)
			if err != nil {
				continue
			}
			latencies = append(latencies, lat)
		}
	}

	return latencies, nil
}

func main() {
	// Example usage
	host := "google.com"
	count := 4

	fmt.Printf("Measuring latency to %s (%d pings)...\n", host, count)

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency to %s: %.2f ms\n", host, avgLatency)
}

