// MeasureLatency pings the specified host a given number of times and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be positive, got %d", count)
	}
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	var cmd *exec.Cmd

	// Different ping command options for different OS
	// Windows uses -n for count, Unix/Linux/macOS use -c
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %v, output: %s", err, string(output))
	}

	return parsePingOutput(string(output))
}

// parsePingOutput extracts the average latency from ping command output.
func parsePingOutput(output string) (float64, error) {
	// Try to parse Unix/Linux/macOS ping summary output
	// Format: round-trip min/avg/max/stddev = 10.123/10.456/11.000/0.500 ms
	// Or: rtt min/avg/max/mdev = 10.123/10.456/11.000/0.500 ms
	unixRe := regexp.MustCompile(`(?:round-trip|rtt)\s+(?:min/avg/max/(?:stddev|mdev))\s*=\s*([\d.]+)/([\d.]+)/([\d.]+)/([\d.]+)\s*ms`)
	if matches := unixRe.FindStringSubmatch(output); len(matches) >= 3 {
		avg, err := strconv.ParseFloat(matches[2], 64)
		if err != nil {
			return 0, fmt.Errorf("failed to parse average latency: %v", err)
		}
		return avg, nil
	}

	// Try to parse Windows ping summary output
	// Format: Minimum = 10ms, Maximum = 10ms, Average = 10ms
	winRe := regexp.MustCompile(`Average\s*=\s*(\d+)\s*ms`)
	if matches := winRe.FindStringSubmatch(output); len(matches) >= 2 {
		avg, err := strconv.ParseFloat(matches[1], 64)
		if err != nil {
			return 0, fmt.Errorf("failed to parse average latency: %v", err)
		}
		return avg, nil
	}

	// Fallback: parse individual ping response lines
	// Unix format: time=10.123 ms
	// Windows format: time=10ms or time<1ms
	return parseIndividualLatencies(output)
}

// parseIndividualLatencies parses individual ping response lines and calculates the average.
func parseIndividualLatencies(output string) (float64, error) {
	// Match time=XX.XXX ms or time=XXms or time<XXms
	re := regexp.MustCompile(`time[<=]([\d.]+)\s*ms`)
	matches := re.FindAllStringSubmatch(output, -1)

	if len(matches) == 0 {
		return 0, fmt.Errorf("no latency data found in ping output")
	}

	var total float64
	var count int
	for _, match := range matches {
		if len(match) >= 2 {
			latency, err := strconv.ParseFloat(match[1], 64)
			if err != nil {
				continue
			}
			total += latency
			count++
		}
	}

	if count == 0 {
		return 0, fmt.Errorf("no valid latency measurements found")
	}

	return total / float64(count), nil
}

