	}

	// Capture both stdout and stderr
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w", err)
	}

	return parsePingOutput(string(output))
}

// parsePingOutput parses the ping command output and extracts the average latency
func parsePingOutput(output string) (float64, error) {
	if runtime.GOOS == "windows" {
		return parseWindowsPingOutput(output)
	}
	return parseUnixPingOutput(output)
}

// parseUnixPingOutput parses ping output from Unix-like systems (Linux, macOS)
func parseUnixPingOutput(output string) (float64, error) {
	// Common patterns for ping statistics on Unix-like systems:
	// Pattern 1: rtt min/avg/max/mdev = 1.234/5.678/9.012/1.234 ms
	// Pattern 2: round-trip min/avg/max/stddev = 1.234/5.678/9.012/1.234 ms
	patterns := []string{
		`rtt min/avg/max/mdev\s*=\s*[\d.]+/([\d.]+)/[\d.]+/[\d.]+\s*ms`,
		`round-trip min/avg/max/stddev\s*=\s*[\d.]+/([\d.]+)/[\d.]+/[\d.]+\s*ms`,
	}

	for _, pattern := range patterns {
		re := regexp.MustCompile(pattern)
		matches := re.FindStringSubmatch(output)
		if len(matches) > 1 {
			avg, err := strconv.ParseFloat(matches[1], 64)
			if err != nil {
				return 0, fmt.Errorf("failed to parse average latency: %w", err)
			}
			return avg, nil
		}
	}

	return 0, fmt.Errorf("could not parse ping output: no latency statistics found")
}

// parseWindowsPingOutput parses ping output from Windows systems
func parseWindowsPingOutput(output string) (float64, error) {
	// Windows ping output format:
	// Minimum = 1ms, Maximum = 9ms, Average = 5ms
	re := regexp.MustCompile(`Average = ([\d.]+)ms`)
	matches := re.FindStringSubmatch(output)
	if len(matches) > 1 {
		avg, err := strconv.ParseFloat(matches[1], 64)
		if err != nil {
			return 0, fmt.Errorf("failed to parse average latency: %w", err)
		}
		return avg, nil
	}

	return 0, fmt.Errorf("could not parse ping output: no latency statistics found")
}

