// parsePingOutput extracts the average latency from ping command output.
func parsePingOutput(output string) (float64, error) {
	// Linux/macOS format: rtt min/avg/max/mdev = 13.8/14.0/14.2/0.15 ms
	// or: round-trip min/avg/max/stddev = 13.8/14.0/14.2/0.15 ms
	linuxPattern := regexp.MustCompile(`(?:rtt|round-trip)\s+(?:min/avg/max/(?:mdev|stddev))\s*=\s*([\d.]+)/([\d.]+)/([\d.]+)/([\d.]+)\s*ms`)
