package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	var cmd *exec.Cmd
	countStr := strconv.Itoa(count)

	// Use platform-specific ping command arguments
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", countStr, host)
	} else {
		cmd = exec.Command("ping", "-c", countStr, host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	outputStr := string(output)

	// Try Unix/Linux/macOS format first
	if avg, err := parseUnixPingOutput(outputStr); err == nil {
		return avg, nil
	}

	// Try Windows format
	if avg, err := parseWindowsPingOutput(outputStr); err == nil {
		return avg, nil
	}

	return 0, errors.New("could not parse ping output: unsupported format")
}

func parseUnixPingOutput(output string) (float64, error) {
	lines := strings.Split(output, "\n")
	var statsLine string
	for _, line := range lines {
		if strings.Contains(line, "rtt min/avg/max") || strings.Contains(line, "round-trip min/avg/max") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// Extract average latency using regex
	// Example lines:
	// - rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	// - round-trip min/avg/max/stddev = 12.345/23.456/34.567/5.678 ms
	// Pattern handles both integers and decimals
	re := regexp.MustCompile(`(?:rtt|round-trip)\s+min/avg/max/\w+\s*=\s*[\d.]+/([\d.]+)/[\d.]+/[\d.]+\s*ms`)
	matches := re.FindStringSubmatch(statsLine)
	if len(matches) < 2 {
		return 0, errors.New("failed to parse average latency from ping output")
	}

	avgStr := matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

func parseWindowsPingOutput(output string) (float64, error) {
	// Windows format: Minimum = 12ms, Maximum = 34ms, Average = 23ms
	re := regexp.MustCompile(`Average\s*=\s*([\d.]+)\s*ms`)
	matches := re.FindStringSubmatch(output)
	if len(matches) < 2 {
		return 0, errors.New("failed to parse average latency from Windows ping output")
	}

	avgStr := matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

func main() {
	// Example usage
	avg, err := MeasureLatency("google.com", 4)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}
	fmt.Printf("Average latency: %.2f ms\n", avg)
}

