// MeasureLatency pings the specified host the given number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be a positive integer")
	}

	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	var cmd *exec.Cmd

	// Build ping command based on OS
	// Windows uses -n for count, Unix/Linux/macOS use -c
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Execute ping command and capture output
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w", err)
	}

	// Parse the output to extract average latency
	return parsePingOutput(string(output))
}

// parsePingOutput extracts the average latency from ping command output
// based on the operating system
func parsePingOutput(output string) (float64, error) {
	if runtime.GOOS == "windows" {
		return parseWindowsPingOutput(output)
	}
	return parseUnixPingOutput(output)
}

// parseUnixPingOutput parses ping output from Unix/Linux/macOS systems
// Expected format: "rtt min/avg/max/mdev = 0.023/0.035/0.047/0.006 ms"
// or on macOS: "round-trip min/avg/max/stddev = 0.023/0.035/0.047/0.006 ms"
func parseUnixPingOutput(output string) (float64, error) {
	// Check for 100% packet loss
	if strings.Contains(output, "100% packet loss") || strings.Contains(output, "100.0% packet loss") {
		return 0, fmt.Errorf("100%% packet loss - host unreachable")
	}

	// Regex pattern to match the statistics line
	// Matches both Linux (rtt) and macOS (round-trip) formats
	re := regexp.MustCompile(`(?:rtt|round-trip)\s+min/avg/max/(?:mdev|stddev)\s*=\s*([\d.]+)/([\d.]+)/([\d.]+)/([\d.]+)\s*ms`)
	matches := re.FindStringSubmatch(output)

	if len(matches) >= 3 {
		avg, err := strconv.ParseFloat(matches[2], 64)
		if err != nil {
			return 0, fmt.Errorf("failed to parse average latency: %w", err)
		}
		return avg, nil
	}

	return 0, fmt.Errorf("could not parse ping output: unrecognized format")
}

// parseWindowsPingOutput parses ping output from Windows systems
// Expected format: "Minimum = 0ms, Maximum = 0ms, Average = 0ms"
func parseWindowsPingOutput(output string) (float64, error) {
	// Check for 100% packet loss
	if strings.Contains(output, "(100% loss)") {
		return 0, fmt.Errorf("100%% packet loss - host unreachable")
	}

	// Regex pattern to match Windows ping statistics
	re := regexp.MustCompile(`Minimum\s*=\s*[\d.]+ms,\s*Maximum\s*=\s*[\d.]+ms,\s*Average\s*=\s*([\d.]+)ms`)
	matches := re.FindStringSubmatch(output)

	if len(matches) >= 2 {
		avg, err := strconv.ParseFloat(matches[1], 64)
		if err != nil {
			return 0, fmt.Errorf("failed to parse average latency: %w", err)
		}
		return avg, nil
	}

	return 0, fmt.Errorf("could not parse ping output: unrecognized format")
}

func main() {
	// Check command line arguments
	if len(os.Args) < 3 {
		fmt.Println("Usage: latency-measure <host> <count>")
		fmt.Println("  host  - The target host to ping (e.g., google.com, 8.8.8.8)")
		fmt.Println("  count - Number of ping attempts (positive integer)")
		fmt.Println()
		fmt.Println("Example: latency-measure google.com 4")
		os.Exit(1)
	}

	host := os.Args[1]

	count, err := strconv.Atoi(os.Args[2])
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: Invalid count '%s' - must be a positive integer\n", os.Args[2])
		os.Exit(1)
	}

	// Measure latency
	fmt.Printf("Pinging %s (%d times)...\n", host, count)
	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error measuring latency: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s: %.2f ms\n", host, avgLatency)
}

