package main

import (
	"bufio"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host a given number of times and returns the average latency in milliseconds.
// It uses the system's ping command and parses the output to extract latency information.
func MeasureLatency(host string, count int) (float64, error) {
	// Validate input parameters
	if count <= 0 {
		return 0, fmt.Errorf("count must be positive, got %d", count)
	}
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	var cmd *exec.Cmd

	// Different ping commands for different operating systems
	switch runtime.GOOS {
	case "windows":
		// Windows uses -n for count
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	default:
		// Linux, macOS, and other Unix-like systems use -c for count
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Execute the ping command and capture both stdout and stderr
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w", err)
	}

	// Parse the ping output to extract latency values
	return parsePingOutput(string(output))
}

// parsePingOutput extracts latency values from ping command output
// and calculates the average latency in milliseconds.
func parsePingOutput(output string) (float64, error) {
	var latencies []float64
	var totalLatency float64

	scanner := bufio.NewScanner(strings.NewReader(output))

	// Regex to match latency in ping output
	// Matches patterns like: time=10.123 ms, time=10ms, time<1ms
	timeRegex := regexp.MustCompile(`time[=<>]([\d.]+)\s*ms`)

	for scanner.Scan() {
		line := scanner.Text()
		matches := timeRegex.FindStringSubmatch(line)
		if len(matches) > 1 {
			latency, err := strconv.ParseFloat(matches[1], 64)
			if err == nil {
				latencies = append(latencies, latency)
				totalLatency += latency
			}
		}
	}

	if err := scanner.Err(); err != nil {
		return 0, fmt.Errorf("error reading ping output: %w", err)
	}

	if len(latencies) == 0 {
		return 0, fmt.Errorf("no latency data found in ping output")
	}

	// Calculate and return the average latency
	return totalLatency / float64(len(latencies)), nil
}

func main() {
	// Example usage with configurable host and count
	host := "google.com"
	count := 4

	fmt.Printf("Measuring latency to %s (%d pings)...\n", host, count)

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s: %.2f ms\n", host, avgLatency)
}

