// MeasureLatency pings the specified host a given number of times and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}
	if count <= 0 {
		return 0, fmt.Errorf("count must be a positive integer")
	}

	var cmd *exec.Cmd

	// Different ping command syntax for different operating systems
	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	default: // linux, darwin, freebsd, etc.
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.Output()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w", err)
	}

	// Parse the output to extract average latency
	return parsePingOutput(string(output))
}

// parsePingOutput extracts the average latency from ping command output.
func parsePingOutput(output string) (float64, error) {
	scanner := bufio.NewScanner(strings.NewReader(output))

	if runtime.GOOS == "windows" {
		// Windows ping output format:
		// "Minimum = 1ms, Maximum = 2ms, Average = 1ms"
		for scanner.Scan() {
			line := scanner.Text()
			if strings.Contains(line, "Average =") {
				parts := strings.Split(line, ",")
				for _, part := range parts {
					part = strings.TrimSpace(part)
					if strings.HasPrefix(part, "Average =") {
						avgPart := strings.TrimPrefix(part, "Average =")
						avgPart = strings.TrimSuffix(avgPart, "ms")
						avgPart = strings.TrimSpace(avgPart)
						return strconv.ParseFloat(avgPart, 64)
					}
				}
			}
		}
	} else {
		// Linux/macOS ping output format:
		// "rtt min/avg/max/mdev = 0.123/0.456/0.789/0.123 ms"
		// or "round-trip min/avg/max/stddev = 0.123/0.456/0.789/0.123 ms"
		for scanner.Scan() {
			line := scanner.Text()
			if strings.Contains(line, "rtt min/avg/max") || strings.Contains(line, "round-trip min/avg/max") {
				parts := strings.Split(line, "=")
				if len(parts) >= 2 {
					valuesPart := strings.TrimSpace(parts[1])
					// Remove "ms" suffix
					valuesPart = strings.TrimSuffix(valuesPart, "ms")
					valuesPart = strings.TrimSpace(valuesPart)
					values := strings.Split(valuesPart, "/")
					if len(values) >= 2 {
						avgStr := strings.TrimSpace(values[1])
						return strconv.ParseFloat(avgStr, 64)
					}
				}
			}
		}
	}

	return 0, fmt.Errorf("could not parse ping output: no average latency found")
}

func main() {
	// Example usage
	host := "google.com"
	count := 4

	fmt.Printf("Measuring latency to %s (%d pings)...\n", host, count)
	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}
	fmt.Printf("Average latency: %.2f ms\n", avgLatency)
}

