	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w, output: %s", err, string(output))
	}

	return parsePingOutput(string(output))
}

// parsePingOutput extracts latency values from ping command output
func parsePingOutput(output string) (float64, error) {
	var latencies []float64
	scanner := bufio.NewScanner(strings.NewReader(output))

	// Regex pattern to match time values in ping output
	// Matches: time=1.23 ms, time=1ms, time<1ms, time=1.234ms
	timeRegex := regexp.MustCompile(`time[=<](\d+\.?\d*)\s*ms`)

