// parsePingOutput extracts the average latency from ping command output
func parsePingOutput(output, goos string) (float64, error) {
	lines := strings.Split(output, "\n")

	if goos == "windows" {
		// Windows format: "    Minimum = 13ms, Maximum = 14ms, Average = 13ms"
		for _, line := range lines {
			line = strings.TrimSpace(line)
			if strings.Contains(line, "Average =") {
				parts := strings.Split(line, ",")
				for _, part := range parts {
					part = strings.TrimSpace(part)
					if strings.HasPrefix(part, "Average =") {
						avgStr := strings.TrimPrefix(part, "Average =")
						avgStr = strings.TrimSuffix(strings.TrimSpace(avgStr), "ms")
						avg, err := strconv.ParseFloat(strings.TrimSpace(avgStr), 64)
						if err != nil {
							return 0, fmt.Errorf("failed to parse average latency: %w", err)
						}
						return avg, nil
					}
				}
			}
		}
	} else {
