		// or "rtt min/avg/max/mdev = 13.8/14.0/14.2/0.15 ms"
		for _, line := range lines {
			if strings.Contains(line, "min/avg/max") {
				idx := strings.Index(line, "=")
				if idx != -1 {
					valuesPart := strings.TrimSpace(line[idx+1:])
					valuesPart = strings.TrimSuffix(valuesPart, "ms")
					valuesPart = strings.TrimSpace(valuesPart)
					values := strings.Split(valuesPart, "/")
					if len(values) >= 2 {
