		return avgLatency, nil
	}

	// Fall back to parsing individual ping responses
	return parseIndividualPings(output)
}

// parsePingStats tries to extract average latency from ping statistics summary.
func parsePingStats(output string) (float64, error) {
	var statsRegex *regexp.Regexp

	if runtime.GOOS == "windows" {
		// Windows: "Minimum = 13ms, Maximum = 15ms, Average = 14ms"
		statsRegex = regexp.MustCompile(`Average\s*=\s*(\d+(?:\.\d+)?)\s*ms`)
	} else {
		// Linux/macOS: "rtt min/avg/max/mdev = 13.8/14.4/15.1/0.6 ms"
		// or "round-trip min/avg/max/stddev = 13.8/14.4/15.1/0.5 ms"
		statsRegex = regexp.MustCompile(`(?:rtt|round-trip)\s+min/avg/max/(?:mdev|stddev)\s*=\s*[\d.]+/([\d.]+)/`)
	}

	matches := statsRegex.FindStringSubmatch(output)
	if len(matches) < 2 {
		return 0, fmt.Errorf("could not find statistics in ping output")
	}

	return strconv.ParseFloat(matches[1], 64)
}

// parseIndividualPings extracts latency by averaging individual ping responses.
func parseIndividualPings(output string) (float64, error) {
	var timeRegex *regexp.Regexp

	if runtime.GOOS == "windows" {
		// Windows: "time=14ms" or "time<1ms"
		timeRegex = regexp.MustCompile(`time[=<](\d+(?:\.\d+)?)\s*ms`)
	} else {
		// Linux/macOS: "time=14.2 ms"
		timeRegex = regexp.MustCompile(`time=([\d.]+)\s*ms`)
	}

	var totalLatency float64
	var count int

	scanner := bufio.NewScanner(strings.NewReader(output))
	for scanner.Scan() {
		line := scanner.Text()
		matches := timeRegex.FindStringSubmatch(line)
		if len(matches) >= 2 {
			latency, err := strconv.ParseFloat(matches[1], 64)
			if err == nil {
				totalLatency += latency
				count++
			}
		}
	}

	if count == 0 {
		return 0, fmt.Errorf("no latency data found in ping output")
	}

	return totalLatency / float64(count), nil
}

func main() {
	if len(os.Args) < 3 {
		fmt.Println("Usage: latency-measure <host> <count>")
		fmt.Println("Example: latency-measure google.com 5")
		os.Exit(1)
	}

	host := os.Args[1]
	count, err := strconv.Atoi(os.Args[2])
	if err != nil {
		fmt.Printf("Error: invalid count value: %v\n", err)
		os.Exit(1)
	}

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s: %.2f ms\n", host, avgLatency)
}

