	re := regexp.MustCompile(`Minimum\s*=\s*(\d+)ms,\s*Maximum\s*=\s*(\d+)ms,\s*Average\s*=\s*(\d+)ms`)
	matches := re.FindStringSubmatch(output)

	if len(matches) >= 4 {
		avg, err := strconv.ParseFloat(matches[3], 64)
		if err != nil {
			return 0, fmt.Errorf("failed to parse average latency: %v", err)
		}
		return avg, nil
	}

	return 0, fmt.Errorf("could not parse ping output")
}

