package main

import (
	"bufio"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host a given number of times and returns
// the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be positive")
	}
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	var cmd *exec.Cmd

	// Use different ping flags depending on the OS
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w", err)
	}

	return parsePingOutput(string(output))
}

// parsePingOutput extracts latency values from ping command output
// and returns the average latency in milliseconds.
func parsePingOutput(output string) (float64, error) {
	// Pattern for Unix-like systems: time=X.XXX ms
	unixPattern := regexp.MustCompile(`time=(\d+\.?\d*)\s*ms`)
	// Pattern for Windows: time=Xms or time<Xms
	windowsPattern := regexp.MustCompile(`time[=<](\d+\.?\d*)ms`)

	var latencies []float64

	scanner := bufio.NewScanner(strings.NewReader(output))
	for scanner.Scan() {
		line := scanner.Text()

		// Try Unix pattern first
		matches := unixPattern.FindStringSubmatch(line)
		if matches == nil {
			// Try Windows pattern
			matches = windowsPattern.FindStringSubmatch(line)
		}

		if len(matches) > 1 {
			latency, err := strconv.ParseFloat(matches[1], 64)
			if err == nil {
				latencies = append(latencies, latency)
			}
		}
	}

	if len(latencies) == 0 {
		return 0, fmt.Errorf("no latency values found in ping output")
	}

	var total float64
	for _, l := range latencies {
		total += l
	}

	return total / float64(len(latencies)), nil
}

func main() {
	// Example usage
	host := "google.com"
	count := 4

	fmt.Printf("Measuring latency to %s (%d pings)...\n", host, count)
	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}
	fmt.Printf("Average latency: %.2f ms\n", avgLatency)
}

